var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......네, 그렇군요.","JPN":"……ええ、そうなんですね。","ENG":"Yes, I see.","TWN":"……是的，可以這麼說。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 스승님께 전달하도록 하죠.","JPN":"わかりました。師匠にお伝えしましょう。","ENG":"Okay, I'll say that to the Master.","TWN":"我知道了。我會轉達給師父的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 호출이라니 무슨 일이지? 급한 작전이라도 있나?","JPN":"急に呼び出してどうしたんだ？　緊急作戦か？","ENG":"Why did you call so suddenly? Is there an urgent mission to complete?","TWN":"突然叫我是有什麼事嗎？緊急作戰？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니요. 작전이 아니라 개인적으로 알려드릴 이야기가 있어서 불렀습니다.","JPN":"いいえ、作戦ではなく個人的に話したいことがあってお越しいただきました。","ENG":"No. This is not about a mission. I called you to tell you something personally.","TWN":"不是，不是作戰，是我個人有件事情想告訴您。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조금 전, 코핀 함의 레이더에 <color=#ffd34c>사냥감</color>의 에너지 시그니처가 감지되었습니다.","JPN":"先ほど、コフィン艦のレーダーに、<color=#ffd34c>獲物</color>のエネルギーシグネチャーが検知されました。","ENG":"A while ago, the Coffin's radar has detected the signature energy of the <color=#ffd34c>Prey</color>.","TWN":"不久前，科芬艦的雷達感知到 <color=#ffd34c>獵物</color>的能量標誌。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사냥감이라고?","JPN":"獲物だって？","ENG":"The Prey?","TWN":"獵物？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......설마?","JPN":"……まさか？","ENG":"Is that what I think it is?","TWN":"……難不成？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 클리포트 인자 반응입니다. 꽤 오랜만의 일이라 조금 당황스럽긴 하군요.","JPN":"はい、クリフォト・ファクター反応です。かなり久々なので、動揺してしまいますね。","ENG":"Yes, the Qliphoth Factor. I'm surprised too, it's been so long.","TWN":"沒錯。是逆卡巴拉因子反應。好久沒遇到這種情況了，還有些慌張呢。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설마, 나유빈 그 녀석이 움직였나......","JPN":"まさか、イチノセ・カオル。あいつが動いたのか……","ENG":"Wait, did Na Yubin make a move?","TWN":"難道，是羅瑜斌那傢伙開始行動了嗎……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다행히도 그건 아닌 것 같습니다.","JPN":"幸いにも、そういうわけではなさそうです。","ENG":"Fortunately, no.","TWN":"所幸並非如此。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자라고는 해도 미나 양의 그것과는 전혀 다른 타입입니다.","JPN":"クリフォト・ファクターとはいっても、ミナさんとは全く別のタイプですね。","ENG":"This Qliphoth Factor is different from Mina's.","TWN":"雖說是逆卡巴拉因子，但它與劉米娜小姐的逆卡巴拉因子類型完全不同。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 활성화된 클리포트 인자라고 하기에는 강도도 약하고...","JPN":"そもそも活性化されたクリフォト・ファクターにしては強度も足りないですし……","ENG":"Its signal strength is too weak for an activated Qliphoth Factor, too.","TWN":"最初活性化的逆卡巴拉因子強度也很弱……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 감지 오류일 수도 있습니다.","JPN":"もしかしたら検知エラーかもしれません。","ENG":"Perhaps this is just a detection error.","TWN":"也有可能是勘測錯誤。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이쪽 정보는 발견하는 즉시 스승님께 최우선으로 전달해 드리는 게 규칙이라서요.","JPN":"ですが、この手の情報は入手次第、師匠に最優先で伝えることになっていますからね。","ENG":"But as a rule, I must inform you of such information before everyone else.","TWN":"但規定是一旦有這方面的情報，就要立刻向師父報告。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 괜한 일이었나요?","JPN":"もしかして、余計でしたか？","ENG":"Shouldn't I have told you?","TWN":"我是不是做了多餘的事？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 괜찮아.","JPN":"いや、いいんだ。","ENG":"You did the right thing telling me.","TWN":"不，沒有關係。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아직 남아있는 녀석이 있었나 보군.","JPN":"まだ生き残りがいたんだな。","ENG":"Clearly, some of them have survived.","TWN":"看來還有剩下的傢伙啊。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};